DATA.forEach((d, i) => (d._i = i + 1));

const fmtMoney = (v, cur) => {
	if (v == null) return null;
	const sym =
		{
			INR: "₹",
			USD: "$",
			EUR: "€",
			GBP: "£",
			JPY: "¥",
			SGD: "S$",
			AED: "AED ",
			TWD: "NT$",
		}[cur] || cur + " ";
	if (cur === "INR") {
		if (v >= 1e7)
			return sym + (v / 1e7).toFixed(2).replace(/\.00$/, "") + " Cr";
		if (v >= 1e5)
			return sym + (v / 1e5).toFixed(2).replace(/\.00$/, "") + " L";
	}
	return sym + v.toLocaleString("en-IN");
};
const esc = (s) =>
	(s || "").replace(
		/[&<>"']/g,
		(c) =>
			({
				"&": "&amp;",
				"<": "&lt;",
				">": "&gt;",
				'"': "&quot;",
				"'": "&#39;",
			})[c],
	);

/* ── facets ── */
function uniqSorted(key) {
	return [...new Set(DATA.map((d) => d[key]).filter(Boolean))].sort((a, b) =>
		a.localeCompare(b),
	);
}
function fill(id, vals, label) {
	const s = document.getElementById(id);
	s.innerHTML =
		'<option value="">' +
		label +
		"</option>" +
		vals.map((v) => `<option>${esc(v)}</option>`).join("");
}
fill("sector", uniqSorted("sector"), "All sectors");
fill("cur", uniqSorted("currency"), "All currencies");
// normalise accommodation to first token
const accVals = [
	...new Set(
		DATA.map((d) => (d.accommodation || "").split(";")[0].trim()).filter(
			Boolean,
		),
	),
].sort();
fill("acc", accVals, "Any");
const bondVals = [
	...new Set(DATA.map((d) => (d.bond === "No" ? "No bond" : "Bonded"))),
];
fill("bond", bondVals.sort(), "Any");

/* ── stats ── */
function computeStats(rows) {
	const inr = rows.filter((d) => d.currency === "INR" && d.ctc);
	const ctcs = inr.map((d) => d.ctc).sort((a, b) => a - b);
	const med = ctcs.length ? ctcs[Math.floor(ctcs.length / 2)] : null;
	const max = ctcs.length ? ctcs[ctcs.length - 1] : null;
	const companies = new Set(rows.map((d) => d.company)).size;
	return {
		n: rows.length,
		companies,
		med,
		max,
		sectors: new Set(rows.map((d) => d.sector).filter(Boolean)).size,
	};
}
function renderStats(rows) {
	const s = computeStats(rows);
	document.getElementById("stats").innerHTML = [
		["v", s.n, "Listings"],
		["v", s.companies, "Companies"],
		["v", s.sectors, "Sectors"],
		["v", fmtMoney(s.med, "INR") || "—", "Median CTC · INR"],
		["v", fmtMoney(s.max, "INR") || "—", "Top CTC · INR"],
	]
		.map(
			([_, v, l]) =>
				`<div class="stat"><div class="v">${v}</div><div class="l">${l}</div></div>`,
		)
		.join("");
}

/* ── histogram (INR CTC) ── */
function renderHist(rows) {
	const vals = rows
		.filter((d) => d.currency === "INR" && d.ctc)
		.map((d) => d.ctc / 1e5); // in lakhs
	const host = document.getElementById("hist"),
		axis = document.getElementById("histAxis");
	if (!vals.length) {
		host.innerHTML = "";
		axis.innerHTML = "";
		document.getElementById("vizNote").textContent = "no INR data";
		return;
	}
	const max = Math.max(...vals),
		bins = 24,
		step = max / bins;
	const buckets = new Array(bins).fill(0);
	vals.forEach((v) => {
		let b = Math.min(bins - 1, Math.floor(v / step));
		buckets[b]++;
	});
	const bmax = Math.max(...buckets);
	host.innerHTML = buckets
		.map((c, i) => {
			const lo = (i * step).toFixed(0),
				hi = ((i + 1) * step).toFixed(0);
			return `<div class="bar" style="height:${(c / bmax) * 100}%"><span class="tip">${c} role${c !== 1 ? "s" : ""} · ₹${lo}–${hi} L</span></div>`;
		})
		.join("");
	axis.innerHTML = `<span>₹0</span><span>₹${(max / 2).toFixed(0)} L</span><span>₹${max.toFixed(0)} L</span>`;
	document.getElementById("vizNote").textContent = vals.length + " INR roles";
}

/* ── sort + filter state ── */
let sortKey = "ctc",
	sortDir = -1;
const els = {
	q: document.getElementById("q"),
	sector: document.getElementById("sector"),
	cur: document.getElementById("cur"),
	acc: document.getElementById("acc"),
	bond: document.getElementById("bond"),
};

function current() {
	const q = els.q.value.trim().toLowerCase();
	let rows = DATA.filter((d) => {
		if (els.sector.value && d.sector !== els.sector.value) return false;
		if (els.cur.value && d.currency !== els.cur.value) return false;
		if (
			els.acc.value &&
			(d.accommodation || "").split(";")[0].trim() !== els.acc.value
		)
			return false;
		if (els.bond.value) {
			const b = d.bond === "No" ? "No bond" : "Bonded";
			if (b !== els.bond.value) return false;
		}
		if (q) {
			const hay = (
				d.company +
				" " +
				d.title +
				" " +
				d.location +
				" " +
				d.sector
			).toLowerCase();
			if (!hay.includes(q)) return false;
		}
		return true;
	});
	rows.sort((a, a2) => {
		let x = a[sortKey],
			y = a2[sortKey];
		if (typeof x === "number" || typeof y === "number") {
			x = x ?? -1;
			y = y ?? -1;
			return (x - y) * sortDir;
		}
		return String(x).localeCompare(String(y)) * sortDir;
	});
	return rows;
}

function render() {
	const rows = current();
	document.getElementById("count").textContent = rows.length;
	document.getElementById("total").textContent = DATA.length;
	const tb = document.getElementById("rows");
	document.getElementById("empty").style.display = rows.length
		? "none"
		: "block";
	tb.innerHTML = rows
		.map((d, i) => {
			const g = fmtMoney(d.gross, d.currency),
				c = fmtMoney(d.ctc, d.currency);
			return `<tr data-id="${d._i - 1}" style="animation-delay:${Math.min(i * 8, 400)}ms">
      <td class="num idx" data-label="#">${d._i}</td>
      <td data-label="Company"><div class="co">${esc(d.company)}</div><div class="ti hide-sm" style="display:none">${esc(d.title)}</div></td>
      <td class="hide-sm" data-label="Role"><span class="ti" style="color:var(--ink2)">${esc(d.title)}</span></td>
      <td class="num money" data-label="Gross">${g || "<span class=dash>—</span>"}</td>
      <td class="num money" data-label="CTC">${c || "<span class=dash>—</span>"}</td>
    </tr>`;
		})
		.join("");
	renderStats(rows);
	renderHist(rows);
	document.querySelectorAll("thead th").forEach((th) => {
		const k = th.dataset.k;
		th.classList.toggle("active", k === sortKey);
		th.querySelector(".ar").textContent =
			k === sortKey ? (sortDir > 0 ? "▲" : "▼") : "";
	});
	document.getElementById("sortlabel").textContent =
		"sorted by " + sortKey + " " + (sortDir > 0 ? "↑" : "↓");
}

/* ── detail page (new tab via blob) ── */
function detailHTML(d) {
	const row = (label, val) =>
		val
			? `<div class="drow"><dt>${esc(label)}</dt><dd>${val}</dd></div>`
			: "";
	const procSteps = (d.process || "")
		.split("|")
		.map((s) => s.trim())
		.filter(Boolean);
	const proc = procSteps.length
		? '<ol class="proc">' +
			procSteps.map((s) => `<li>${esc(s)}</li>`).join("") +
			"</ol>"
		: "";
	const money = (v) => fmtMoney(v, d.currency) || "—";
	const closes = d.closes
		? new Date(d.closes).toLocaleString("en-IN", {
				dateStyle: "medium",
				timeStyle: "short",
			})
		: "";
	const paras = (t) =>
		esc(t)
			.replace(/\n{2,}/g, "</p><p>")
			.replace(/\n/g, "<br>");
	return `<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1">
  <title>${esc(d.company)} · ${esc(d.title)}</title>
  <style>
  @import url('https://fonts.googleapis.com/css2?family=Fraunces:opsz,wght@9..144,400;9..144,600;9..144,900&family=Spline+Sans+Mono:wght@400;500;600&display=swap');
  :root{--paper:#f4efe6;--paper2:#ece5d6;--ink:#1a1714;--ink2:#5c5347;--line:#cdc3ad;--accent:#b5361f;--accent2:#1f5c4d}
  *{box-sizing:border-box;margin:0;padding:0}
  body{background:var(--paper);color:var(--ink);font-family:'Spline Sans Mono',monospace;line-height:1.6;font-size:14px}
  .wrap{max-width:820px;margin:0 auto;padding:40px 24px 80px}
  .back{font-size:11px;letter-spacing:.12em;text-transform:uppercase;color:var(--accent);text-decoration:none;border-bottom:1px solid transparent}
  .back:hover{border-color:var(--accent)}
  .kick{font-size:11px;letter-spacing:.3em;text-transform:uppercase;color:var(--ink2);margin:26px 0 4px}
  h1{font-family:'Fraunces',serif;font-weight:900;font-size:clamp(30px,5vw,52px);line-height:1;letter-spacing:-.02em;margin-bottom:6px}
  .role{font-family:'Fraunces',serif;font-style:italic;font-size:20px;color:var(--accent);margin-bottom:24px}
  .pay{display:flex;gap:0;border:1px solid var(--ink);margin:22px 0 30px}
  .pay div{flex:1;padding:16px 18px;border-right:1px solid var(--line)}
  .pay div:last-child{border-right:none}
  .pay .l{font-size:10px;letter-spacing:.15em;text-transform:uppercase;color:var(--ink2)}
  .pay .v{font-family:'Fraunces',serif;font-weight:600;font-size:26px;margin-top:4px}
  dl{border-top:1px solid var(--line);margin:24px 0}
  .drow{display:grid;grid-template-columns:200px 1fr;border-bottom:1px solid var(--line)}
  .drow dt{padding:13px 0;font-size:10px;letter-spacing:.14em;text-transform:uppercase;color:var(--ink2)}
  .drow dd{padding:13px 0}
  h2{font-family:'Fraunces',serif;font-weight:600;font-size:22px;margin:40px 0 12px;padding-bottom:6px;border-bottom:2px solid var(--ink)}
  .proc{list-style:none;counter-reset:s}
  .proc li{counter-increment:s;padding:9px 0 9px 42px;position:relative;border-bottom:1px dotted var(--line)}
  .proc li::before{content:counter(s,decimal-leading-zero);position:absolute;left:0;top:9px;font-family:'Fraunces',serif;font-weight:600;color:var(--accent)}
  .body p{margin:0 0 14px}
  .apply{display:inline-block;margin-top:24px;background:var(--ink);color:var(--paper);padding:12px 22px;text-decoration:none;font-size:11px;letter-spacing:.12em;text-transform:uppercase}
  .apply:hover{background:var(--accent)}
  .none{color:var(--ink2);font-style:italic}
  </style></head><body><div class="wrap">
  <a class="back" href="javascript:window.close()">✕ Close tab</a>
  <div class="kick">${esc(d.sector || "Listing")}</div>
  <h1>${esc(d.company)}</h1>
  <div class="role">${esc(d.title)}</div>
  <div class="pay">
    <div><div class="l">Gross · p.a.</div><div class="v">${money(d.gross)}</div></div>
    <div><div class="l">CTC · p.a.</div><div class="v">${money(d.ctc)}</div></div>
    <div><div class="l">Currency</div><div class="v">${esc(d.currency || "—")}</div></div>
  </div>
  <dl>
    ${row("Place of Posting", esc(d.location))}
    ${row("Accommodation", esc(d.accommodation))}
    ${row("Bond", d.bond === "No" ? "No bond" : esc(d.bond) + " months")}
    ${row("CPI Cutoff", d.cpi && d.cpi !== "None" ? esc(d.cpi) : "None")}
    ${row("Applications Close", esc(closes))}
  </dl>
  ${proc ? "<h2>Selection Process</h2>" + proc : ""}
  <h2>Job Details</h2>
  <div class="body">${d.details ? "<p>" + paras(d.details) + "</p>" : "<p class=none>No description provided.</p>"}</div>
  ${d.info ? '<h2>Additional Information</h2><div class="body"><p>' + paras(d.info) + "</p></div>" : ""}
  ${d.reqs ? '<h2>Additional Requirements</h2><div class="body"><p>' + paras(d.reqs) + "</p></div>" : ""}
  </div></body></html>`;
}
function openDetail(id) {
	const d = DATA[id];
	const blob = new Blob([detailHTML(d)], { type: "text/html" });
	window.open(URL.createObjectURL(blob), "_blank");
}

/* ── events ── */
document.getElementById("rows").addEventListener("click", (e) => {
	const tr = e.target.closest("tr");
	if (tr) openDetail(+tr.dataset.id);
});
document.querySelectorAll("thead th").forEach((th) =>
	th.addEventListener("click", () => {
		const k = th.dataset.k;
		if (k === sortKey) sortDir *= -1;
		else {
			sortKey = k;
			sortDir = k === "company" || k === "title" ? 1 : -1;
		}
		render();
	}),
);
Object.values(els).forEach((el) => el.addEventListener("input", render));
document.getElementById("reset").addEventListener("click", () => {
	els.q.value = "";
	["sector", "cur", "acc", "bond"].forEach((k) => (els[k].value = ""));
	sortKey = "ctc";
	sortDir = -1;
	render();
});

/* ── mobile sort controls ── */
const mobileSortSelect = document.getElementById("mobileSortSelect");
const mobileSortControls = document.getElementById("mobileSortControls");

function updateMobileSortVisibility() {
	mobileSortControls.style.display =
		window.innerWidth <= 480 ? "flex" : "none";
}

mobileSortSelect.addEventListener("change", (e) => {
	const newKey = e.target.value;
	if (newKey === sortKey) {
		sortDir *= -1;
	} else {
		sortKey = newKey;
		sortDir = newKey === "company" || newKey === "title" ? 1 : -1;
	}
	render();
});

window.addEventListener("resize", updateMobileSortVisibility);
updateMobileSortVisibility();

render();
